  const paypalRoute = await import('@/app/api/webhooks/paypal/route')
  paypalWebhookHandler = paypalRoute.POST

  // Create tenant
  const tenant = await payload.create({
    collection: 'tenants',
    data: { name: `webhook-test-${Date.now()}`, slug: `webhook-test-${Date.now()}` } as any,
